                                    {openMenuId === acc.id && (
                                        <>
                                            <div className="fixed inset-0 z-40" onClick={() => setOpenMenuId(null)}></div>
                                            <div className="absolute left-0 mt-2 w-48 bg-slate-900 border border-white/10 rounded-xl shadow-2xl z-50 overflow-hidden animate-fade-in origin-top-left">
                                                <button onClick={(e) => { e.stopPropagation(); setModal({ type: 'details', account: acc }); setOpenMenuId(null); }} className="flex items-center gap-3 w-full text-right px-4 py-3.5 text-sm text-cyan-400 font-bold hover:bg-white/5 border-b border-white/5 transition">
                                                    <InformationCircleIcon className="w-5 h-5"/> التفاصيل والمعاملات
