                                    </button>
                                    <button onClick={() => { onDelete(); setIsMenuOpen(false); }} className="flex items-center gap-3 w-full text-right px-4 py-3 text-sm text-rose-400 hover:bg-white/10 transition">
                                        <TrashIcon className="w-4 h-4"/> حذف الحساب
